import sys
import math

MOD = 998244353

def input():
    return sys.stdin.readline().rstrip()

def getNM():
    return map(int, input().split())

def main():
    N, M = getNM()
    l = 1
    ans = 0
    all_arrays = 1  # counts M^i for arrays of length i
    non_ambiguous = 1  # counts product_{k=1 to i} floor(M / lcm(1..k))

    for i in range(1, N + 1):
        if math.gcd(l, i) == 1:
            l *= i
        all_arrays = (all_arrays * (M % MOD)) % MOD
        non_ambiguous = (non_ambiguous * ((M // l) % MOD)) % MOD
        ans = (ans + all_arrays - non_ambiguous) % MOD
    print(ans)

if __name__ == "__main__":
    main()
